import React from "react";
import IntroSection from "./NosotrosSection";
import ImageSection from "./ImageSection";
import ProblemSection from "./VisionSection";
import HeroSection from "./MisionSection";
import TestimonialsSection from "./PersonalSection";

const AboutUsContainer = () => {
  return (
    <main style={{ backgroundColor: "#f8f2e7", color: "#003E73", padding: "3rem 1rem" }}>
      <IntroSection />
      <ProblemSection />
      <HeroSection />
      <TestimonialsPersonalSectionSection />
    </main>
  );
};

export default AboutUsContainer;
